SELECT COUNT(DISTINCT country_id) AS Countries_with_high_inflation 
FROM economic_indicators 
WHERE inflation_rate > 5;

external_knowledge:
- "bucolic realms of high income and moderate economic equality" refers to countries with high income levels and a GINI coefficient below 30, indicating lower income inequality;
- "financial prosperity" means GDP per capita in PPP;
- "societal equity" refers to the GINI coefficient, a measure of income inequality;
- "carbon footprint" is measured by CO2 emissions per capita;
- "commitment to green energy" is represented by the share of renewable energy in the energy mix;
- "ordered by their lesser economic divides" means sorted by the GINI coefficient in ascending order.

